mapper.select:
select
    bill_id, owner_id, owner_name, pay_method,
    transaction_no, status, community_id, create_time
from community_payment_record
where bill_id = #{billId}
  and owner_id = #{ownerId}
  and owner_name like concat('%', #{ownerName}, '%')
  and pay_method = #{payMethod}
  and transaction_no = #{transactionNo}
  and status = #{status}
  and community_id = #{communityId}
order by create_time desc

mapper.insert:
insert into community_payment_record (
    bill_id, owner_id, owner_name, pay_amount, pay_method,
    transaction_no, pay_time, status, community_id,
    create_by, create_time, update_by, update_time, remark
) values (
             #{billId}, #{ownerId}, #{ownerName}, #{payAmount}, #{payMethod},
             #{transactionNo}, #{payTime}, #{status}, #{communityId},
             #{createBy}, #{createTime}, #{updateBy}, #{updateTime}, #{remark}
         )
